const floor = Number(env.get('FLOOR_NUMBER') || 0);
if (floor === 0) return null;
const floorstr = floor.toString().padStart(2, '0');
return {
    action: 'subscribe',
    topic: `campus/b01/f${floorstr}/+/telemetry`,
    qos: 0
};

let payload = msg.payload;
if (typeof payload === 'string') {
    try {
        payload = JSON.parse(payload);
    } catch (e) {
        node.error('MQTT payload parse failed: ' + e.message, msg);
        return null;
    }
}
if (!payload || !payload.deviceName) return null;

const hvac = payload.hvac_mode;
const telemetry = JSON.stringify({
    [payload.deviceName]: [
        {
            ts: Date.now(),
            values: {
                temperature: payload.temperature,
                humidity: payload.humidity,
                occupancy: payload.occupancy,
                light_level: payload.light_level,
                hvac_mode: hvac,
                hvac_status: hvac,
                lighting_dimmer: payload.lighting_dimmer
            }
        }
    ]
});

const connect = JSON.stringify({ device: payload.deviceName });
return [
    { payload: telemetry },
    { payload: connect },
    { payload: payload }
];

const floor = Number(env.get('FLOOR_NUMBER') || 0);
if (floor === 0) return null;
const floorOffset = (floor - 1) * 20;
const floorstr = floor.toString().padStart(2, '0');
const coapHost = env.get('COAP_HOST') || 'campus_engine';
for (let room = 1; room <= 20; room++) {
    const roomId = floorOffset + room;
    const port = 5700 + roomId - 1;
    node.send({
        url: `coap://${coapHost}:${port}/payload`,
        method: 'GET',
        roomId: `b01-f${floorstr}-r${roomId.toString().padStart(3, '0')}`
    });
}
return null;

let data;
if (typeof msg.payload === 'object' && !Buffer.isBuffer(msg.payload)) {
    data = msg.payload;
} else {
    const raw = Buffer.isBuffer(msg.payload) ? msg.payload.toString('utf8') : msg.payload;
    try {
        data = JSON.parse(raw);
    } catch (e) {
        node.error('CoAP JSON parse failed: ' + e.message, msg);
        return null;
    }
}

const deviceName = data.metadata.sensor_id + '-COAP';
const hvac = data.actuators.hvac_mode;
const telemetry = JSON.stringify({
    [deviceName]: [
        {
            ts: Date.now(),
            values: {
                temperature: data.sensors.temperature,
                humidity: data.sensors.humidity,
                occupancy: data.sensors.occupancy,
                light_level: data.sensors.light_level,
                hvac_mode: hvac,
                hvac_status: hvac,
                lighting_dimmer: data.actuators.lighting_dimmer
            }
        }
    ]
});
const connect = JSON.stringify({ device: deviceName });
return [
    { payload: telemetry },
    { payload: connect },
    { payload: data }
];

let rooms = flow.get("rooms") || Array.from({ length: 20 }, () => ({
    count: 0,
    temp_sum: 0,
    humidity_sum: 0,
    occupancy: 0,
    light_level: 0,
    hvac_mode: 'off',
    hvac_status: 'off',
    lighting_dimmer: 0
}));

const curr_room = (msg.payload.metadata.room - 1) % 20;
const room = rooms[curr_room];
const sensors = msg.payload.sensors || {};
const actuators = msg.payload.actuators || {};

room.count++;
room.temp_sum += Number(sensors.temperature || 0);
room.humidity_sum += Number(sensors.humidity || 0);
if (sensors.occupancy !== undefined) room.occupancy = sensors.occupancy;
if (sensors.light_level !== undefined) room.light_level = sensors.light_level;
if (actuators.hvac_mode !== undefined) {
    room.hvac_mode = actuators.hvac_mode;
    room.hvac_status = actuators.hvac_mode;
}
if (actuators.lighting_dimmer !== undefined) room.lighting_dimmer = actuators.lighting_dimmer;

flow.set("rooms", rooms);
msg.payload = room;
return msg;

let rooms = flow.get("rooms") || Array.from({ length: 20 }, () => ({
    count: 0,
    temp_sum: 0,
    humidity_sum: 0,
    occupancy: 0,
    light_level: 0,
    hvac_mode: 'off',
    hvac_status: 'off',
    lighting_dimmer: 0
}));

const curr_room = (msg.payload.room - 1) % 20;
const room = rooms[curr_room];

room.count++;
room.temp_sum += Number(msg.payload.temperature || 0);
room.humidity_sum += Number(msg.payload.humidity || 0);
if (msg.payload.occupancy !== undefined) room.occupancy = msg.payload.occupancy;
if (msg.payload.light_level !== undefined) room.light_level = msg.payload.light_level;
if (msg.payload.hvac_mode !== undefined) {
    room.hvac_mode = msg.payload.hvac_mode;
    room.hvac_status = msg.payload.hvac_mode;
}
if (msg.payload.hvac_status !== undefined) room.hvac_status = msg.payload.hvac_status;
if (msg.payload.lighting_dimmer !== undefined) room.lighting_dimmer = msg.payload.lighting_dimmer;

flow.set("rooms", rooms);
msg.payload = room;
return msg;

const floor = Number(env.get("FLOOR_NUMBER") || 0);
if (floor === 0) return null;
const floorOffset = (floor - 1) * 20;
const floorstr = floor.toString().padStart(2, '0');
let rooms = flow.get("rooms") || Array.from({ length: 20 }, () => ({
    count: 0,
    temp_sum: 0,
    humidity_sum: 0,
    occupancy: 0,
    light_level: 0,
    hvac_mode: 'off',
    hvac_status: 'off',
    lighting_dimmer: 0
}));

for (let i = 0; i < 20; i++) {
    const room = rooms[i];
    const count = room.count || 0;
    const roomId = floorOffset + i + 1;
    let deviceName;
    if(!(i%2)) {deviceName = `b01-f${floorstr}-r${roomId.toString().padStart(3, '0')}`}
    else { deviceName = `b01-f${floorstr}-r${roomId.toString().padStart(3, '0')}-COAP` }

    node.send({
        payload: JSON.stringify({
            [deviceName]: [
                {
                    ts: Date.now(),
                    values: {
                        temperature: count > 0 ? room.temp_sum / count : 0,
                        humidity: count > 0 ? room.humidity_sum / count : 0,
                        occupancy: room.occupancy,
                        light_level: room.light_level,
                        hvac_mode: room.hvac_mode,
                        hvac_status: room.hvac_status,
                        lighting_dimmer: room.lighting_dimmer
                    }
                }
            ]
        })
    });
}

flow.set("rooms", undefined);
return null;

const floor = Number(env.get('FLOOR_NUMBER') || 0);
if (floor === 0) return null;
const floorstr = floor.toString().padStart(2, '0');
return {
    action: 'subscribe',
    topic: `campus/b01/cmd/f${floorstr}/+`,
    qos: 2
};

const topic = msg.topic || '';
const match = topic.match(/^campus\/b01\/cmd\/f(\d{2})\/r(\d{3})$/);
if (!match) return null;

let payload = msg.payload;
if (typeof payload === 'string') {
    try {
        payload = JSON.parse(payload);
    } catch (e) {
        node.error('Command payload parse failed: ' + e.message, msg);
        return null;
    }
}

const floorNum = parseInt(match[1], 10);
const roomNum = parseInt(match[2], 10);
const transport = payload.transport || 'mqtt';
const deviceName = payload.device_name || `b01-f${match[1]}-r${match[2]}`;
const commandId = payload.command_id;
if (!commandId) {
    node.error('Missing command_id for floor command', msg);
    return null;
}

const pending = flow.get('pendingRpcAcks') || {};
const state = pending[commandId];
if (!state) {
    node.warn(`No pending RPC state for command_id ${commandId}`);
    return null;
}

if (transport === 'coap') {
    return [null, {
        topic,
        payload,
        floorNum,
        roomNum,
        deviceName,
        _rpc: {
            commandId,
            deviceName: state.deviceName,
            rpcId: state.rpcId,
            startedAt: state.startedAt,
            requested: state.requested
        }
    }];
}

return [{
    topic: `campus/b01/cmd/${deviceName}`,
    payload: JSON.stringify({
        ...payload,
        command_id: commandId
    })
}, null];

const roomNum = Number(msg.roomNum);
if (!roomNum) return null;

const payload = msg.payload || {};
const coapHost = env.get('COAP_HOST') || 'campus_engine';
const cmdPayload = {};
let actuator = null;
if (payload.hvac_mode !== undefined) {
    cmdPayload.hvac_mode = payload.hvac_mode;
    actuator = 'hvac';
}
if (payload.lighting_dimmer !== undefined) {
    cmdPayload.lighting_dimmer = payload.lighting_dimmer;
    actuator = 'light_dimmer';
}
if (!actuator) return null;

msg.url = `coap://${coapHost}:${5700 + roomNum - 1}/actuator/${actuator}`;
msg.method = 'PUT';
msg.payload = cmdPayload;
return msg;

const floor = Number(env.get('FLOOR_NUMBER') || 0);
if (floor === 0) return null;
const floorstr = floor.toString().padStart(2, '0');
node.send({ action: 'subscribe', topic: `campus/b01/f${floorstr}/+/ack/hvac_applied`, qos: 2 });
node.send({ action: 'subscribe', topic: `campus/b01/f${floorstr}/+/ack/light_dimmer_applied`, qos: 2 });
return null;

let payload = msg.payload;
if (typeof payload === 'string') {
    try {
        payload = JSON.parse(payload);
    } catch (e) {
        node.error('MQTT ack parse failed: ' + e.message, msg);
        return null;
    }
}

const commandId = payload && payload.command_id;
if (!commandId) return null;

const pending = flow.get('pendingRpcAcks') || {};
const state = pending[commandId];
if (!state) return null;

delete pending[commandId];
flow.set('pendingRpcAcks', pending);

const rttMs = Date.now() - state.startedAt;
const ackValues = {
    rtt_ms: rttMs
};
if (payload.hvac_mode !== undefined) {
    ackValues.hvac_mode = String(payload.hvac_mode).toLowerCase();
    ackValues.hvac_status = String(payload.hvac_mode).toLowerCase();
}
if (payload.lighting_dimmer !== undefined) {
    ackValues.lighting_dimmer = payload.lighting_dimmer;
}
if (state.requested !== undefined) {
    ackValues.requested_value = state.requested;
}

return [
    {
        payload: JSON.stringify({
            device: state.deviceName,
            id: state.rpcId,
            data: {
                success: true,
                state: payload.hvac_mode !== undefined ? String(payload.hvac_mode).toLowerCase() : payload.lighting_dimmer,
                rtt_ms: rttMs,
                ack: payload
            }
        })
    },
    {
        payload: JSON.stringify({
            [state.deviceName]: [
                {
                    ts: Date.now(),
                    values: ackValues
                }
            ]
        })
    },
    {
        payload: {
            source: 'mqtt-ack',
            command_id: commandId,
            device: state.deviceName,
            rtt_ms: rttMs,
            ack: payload
        }
    }
];

const floor = Number(env.get('FLOOR_NUMBER') || 0);
if (floor === 0) return null;

let body = msg.payload;
if (typeof body === 'string') {
    try {
        body = JSON.parse(body);
    } catch (e) {
        node.error('TB RPC parse failed: ' + e.message, msg);
        return null;
    }
}

const fullDeviceName = body.device;
const rpcData = body.data || {};
const method = rpcData.method;
const params = rpcData.params;
const rpcId = rpcData.id;
if (!fullDeviceName || rpcId === undefined) return null;

const isCoap = fullDeviceName.endsWith('-COAP');
const deviceName = isCoap ? fullDeviceName.replace(/-COAP$/, '') : fullDeviceName;
const deviceMatch = deviceName.match(/^b01-f(\d{2})-r(\d{3})$/);
if (!deviceMatch) {
    node.error('Unsupported device name format: ' + fullDeviceName, msg);
    return null;
}

let cmdPayload = null;
let ackTopic = null;
if (method === 'hvac' || method === 'hvac_mode') {
    cmdPayload = { hvac_mode: typeof params === 'object' ? params.hvac_mode : params };
    ackTopic = 'hvac_applied';
} else if (method === 'light_dimmer' || method === 'lighting_dimmer') {
    const rawValue = typeof params === 'object' ? params.lighting_dimmer : params;
    cmdPayload = { lighting_dimmer: parseInt(rawValue, 10) };
    ackTopic = 'light_dimmer_applied';
}
if (!cmdPayload) return null;

const commandId = `${fullDeviceName}:${rpcId}:${Date.now()}`;
const pending = flow.get('pendingRpcAcks') || {};
pending[commandId] = {
    deviceName: fullDeviceName,
    rpcId,
    startedAt: Date.now(),
    requested: Object.values(cmdPayload)[0],
    ackTopic
};
flow.set('pendingRpcAcks', pending);

return {
    topic: `campus/b01/cmd/f${deviceMatch[1]}/r${deviceMatch[2]}`,
    payload: JSON.stringify({
        ...cmdPayload,
        command_id: commandId,
        device_name: deviceName,
        transport: isCoap ? 'coap' : 'mqtt'
    })
};

const rpc = msg._rpc;
if (!rpc || !rpc.commandId) return null;

let payload = msg.payload;
if (Buffer.isBuffer(payload)) {
    payload = payload.toString('utf8');
}
if (typeof payload === 'string') {
    try {
        payload = JSON.parse(payload);
    } catch (e) {
        node.error('CoAP ack parse failed: ' + e.message, msg);
        return null;
    }
}

const pending = flow.get('pendingRpcAcks') || {};
delete pending[rpc.commandId];
flow.set('pendingRpcAcks', pending);

const rttMs = Date.now() - rpc.startedAt;
const ackValues = { rtt_ms: rttMs };
if (payload.hvac_mode !== undefined) {
    ackValues.hvac_mode = String(payload.hvac_mode).toLowerCase();
    ackValues.hvac_status = String(payload.hvac_mode).toLowerCase();
}
if (payload.lighting_dimmer !== undefined) {
    ackValues.lighting_dimmer = payload.lighting_dimmer;
}
if (payload.ambient !== undefined) {
    ackValues.light_level = payload.ambient;
}
if (rpc.requested !== undefined) {
    ackValues.requested_value = rpc.requested;
}

return [
    {
        payload: JSON.stringify({
            device: rpc.deviceName,
            id: rpc.rpcId,
            data: {
                success: true,
                state: payload.hvac_mode !== undefined ? String(payload.hvac_mode).toLowerCase() : payload.lighting_dimmer,
                rtt_ms: rttMs,
                ack: payload
            }
        })
    },
    {
        payload: JSON.stringify({
            [rpc.deviceName]: [
                {
                    ts: Date.now(),
                    values: ackValues
                }
            ]
        })
    },
    {
        payload: {
            source: 'coap-ack',
            command_id: rpc.commandId,
            device: rpc.deviceName,
            rtt_ms: rttMs,
            ack: payload
        }
    }
];
